section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/diary-study-execution.json",
  "title": "Diary Study Execution and Analysis",
  "type": "object",
  "required": [
    "artefact_id",
    "compliance_log",
    "low_quality_entries",
    "codebook",
    "coded_entries",
    "temporal_patterns",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "compliance_log": {
      "type": "array",
      "description": "per-participant entry counts + flags",
      "minItems": 1
    },
    "low_quality_entries": {
      "type": "array",
      "description": "{entry_id, reason, action}",
      "minItems": 1
    },
    "codebook": {
      "type": "object",
      "description": "code -> definition"
    },
    "coded_entries": {
      "type": "array",
      "description": "{entry_id, codes}",
      "minItems": 1
    },
    "temporal_patterns": {
      "type": "array",
      "description": "time-anchored cross-participant patterns",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "diary-study-execution-2026-05-23",
  "compliance_log": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "low_quality_entries": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "codebook": {
    "key": "value"
  },
  "coded_entries": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "temporal_patterns": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
